import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface PickingRule {
  id: string;
  name: string;
  description: string;
}

export interface Order {
  id: string;
  orderNo: string;
  customer: string;
  status: 'pending' | 'processing' | 'shipped';
  itemsCount: number;
  priority: 'High' | 'Medium' | 'Low';
  createdAt: string;
}

export interface GenerationSummary {
  eligibleOrders: number;
  expectedTasks: number;
  rules: PickingRule[];
}

import React from 'react';
import { X, Info, ChevronRight, CheckCircle2 } from 'lucide-react';
import { GenerationSummary } from '../types';

interface PickingConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  summary: GenerationSummary;
}

const PickingConfirmationModal: React.FC<PickingConfirmationModalProps> = ({ 
  isOpen, 
  onClose, 
  onConfirm, 
  summary 
}) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 overflow-hidden">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose} 
      />

      {/* Modal Container */}
      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-lg transform transition-all flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50 rounded-t-2xl">
          <h3 className="text-lg font-semibold text-slate-800">策略生成集合拣货单确认</h3>
          <button 
            onClick={onClose}
            className="p-1 hover:bg-slate-200 rounded-full transition-colors text-slate-400 hover:text-slate-600"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="px-6 py-8 overflow-y-auto">
          <div className="flex items-start gap-4 mb-6">
            <div className="bg-blue-50 p-2.5 rounded-full text-blue-600 shrink-0">
              <Info size={24} />
            </div>
            <div>
              <p className="text-slate-700 leading-relaxed text-[15px]">
                根据配置策略，当前有 <span className="font-bold text-blue-600 text-lg mx-0.5">{summary.eligibleOrders}</span> 单满足生成拣货任务，
                按照以下规则生成 <span className="font-bold text-blue-600 text-lg mx-0.5">{summary.expectedTasks}</span> 个拣货任务，
                请确认是否生成？
              </p>
            </div>
          </div>

          <div className="bg-slate-50 rounded-xl p-4 border border-slate-100 space-y-3">
            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">应用的拣货规则</h4>
            {summary.rules.map((rule) => (
              <div key={rule.id} className="flex items-center gap-3 bg-white p-3 rounded-lg border border-slate-200 shadow-sm transition-all hover:border-blue-200">
                <div className="h-2 w-2 rounded-full bg-blue-500"></div>
                <div>
                  <div className="text-sm font-semibold text-slate-700">{rule.name}</div>
                  <div className="text-xs text-slate-500">{rule.description}</div>
                </div>
                <ChevronRight className="ml-auto text-slate-300" size={16} />
              </div>
            ))}
          </div>
        </div>

        {/* Footer */}
        <div className="px-6 py-5 border-t border-slate-100 flex justify-end gap-3 bg-white rounded-b-2xl">
          <button
            onClick={onClose}
            className="px-5 py-2.5 text-sm font-medium text-slate-600 hover:bg-slate-100 rounded-lg transition-all"
          >
            取消
          </button>
          <button
            onClick={onConfirm}
            className="flex items-center gap-2 px-6 py-2.5 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 active:scale-95 rounded-lg shadow-lg shadow-blue-200 transition-all"
          >
            <CheckCircle2 size={18} />
            确认生成
          </button>
        </div>
      </div>
    </div>
  );
};

export default PickingConfirmationModal;

